struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Use operator[] to peek at the first byte (data_type)
    uint8_t data_type = adaptor[0];

    // Check if buffer has enough data for header (1 byte data_type + 4 bytes item_count)
    if (adaptor.size() < 5) {
        return DataResult{0, {}, {}};
    }

    // Read item_count from position 1 in the buffer
    uint32_t item_count = adaptor[1];

    // Create appropriate vector based on data_type
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;

    if (data_type == 0) {
        int_items.resize(item_count);
    } else if (data_type == 1) {
        float_items.resize(item_count);
    }

    // Create binary_stream for reading
    hexi::pmc::binary_stream stream(adaptor);

    // Read items based on data_type
    for (uint32_t i = 0; i < item_count; ++i) {
        if (data_type == 0) {
            uint32_t value;
            stream >> value;
            int_items[i] = value;
        } else {
            float value;
            stream >> value;
            float_items[i] = value;
        }
    }

    return DataResult{data_type, std::move(int_items), std::move(float_items)};
}
